from enum import Enum
from plum import dispatch
from typing import TypeVar, Union, Generic, List, Tuple
from spire.pdf.common import *
from spire.pdf import *
from ctypes import *
import abc

class PdfFileLinkAnnotationWidget(PdfStyledAnnotationWidget):
    """
    Represents the loaded file link annotation class.
    """

    @property
    def FileName(self) -> str:
        """
        Gets or sets the filename of the annotation.
        """
        GetDllLibPdf().spr_pdf_PdfFileLinkAnnotationWidget_get_FileName.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_PdfFileLinkAnnotationWidget_get_FileName.restype = c_void_p
        ret = PtrToStr(CallCFunction(GetDllLibPdf().spr_pdf_PdfFileLinkAnnotationWidget_get_FileName,self.Ptr))
        return ret

    @FileName.setter
    def FileName(self, value: str):
        """
        Sets the filename of the annotation.
        """
        GetDllLibPdf().spr_pdf_PdfFileLinkAnnotationWidget_set_FileName.argtypes = [c_void_p, c_wchar_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfFileLinkAnnotationWidget_set_FileName,self.Ptr, value)

    def ObjectID(self) -> int:
        """
        Represents the Form field identifier.
        """
        GetDllLibPdf().spr_pdf_PdfFileLinkAnnotationWidget_ObjectID.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_PdfFileLinkAnnotationWidget_ObjectID.restype = c_int
        ret = CallCFunction(GetDllLibPdf().spr_pdf_PdfFileLinkAnnotationWidget_ObjectID,self.Ptr)
        return ret